                let ci_idx =
                    prep_call_info(state, func_idx, nresults, 0, func_idx + 1 + fsize as i32)?;

                // C: ci->u.l.savedpc = p->code  (starting point — offset 0)
                // TODO(port): same as in pretailcall — offset 0 = first instruction.
                state.set_ci_savedpc(ci_idx, 0);

