//! Lua virtual machine — port of `src/lvm.c` (1899 lines, 32 functions).
//!
//! This module implements:
//! - Number coercion helpers (tonumber_, flttointeger, tointegerns, tointeger)
//! - Numeric `for`-loop preparation and stepping (forlimit, forprep, floatforloop)
//! - Table get/set with metamethod chaining (finishget, finishset)
//! - String comparison respecting embedded NULs (l_strcmp)
//! - Relational operators: lessthan, lessequal, equalobj (with metamethods)
//! - String concatenation (concat)
//! - Object length operator (objlen)
//! - Integer arithmetic: idiv, mod, modf, shiftl
//! - Closure creation (pushclosure)
//! - Yield-resume bridge (finishOp)
//! - Main interpreter loop (execute) — the Lua bytecode dispatch engine.
//!
//! # Control flow note
//! The C source uses `goto startfunc` / `goto returning` / `goto ret` across
//! labelled points in `luaV_execute`. These are modelled with Rust's labelled
//! loops (`'startfunc`, `'returning`, `'dispatch`) and `continue`/`break`
//! on those labels.  See inline `PORT NOTE` comments.

// C: #include "lprefix.h"
// C: #include "lua.h"
// C: #include "ldebug.h" "ldo.h" "lfunc.h" "lgc.h" "lobject.h"
// C: #include "lopcodes.h" "lstate.h" "lstring.h" "ltable.h" "ltm.h" "lvm.h"

#[allow(unused_imports)] use crate::prelude::*;
use lua_types::{
    CallInfoIdx, GcRef, LuaError, LuaValue, StackIdx,
};
use lua_types::tagmethod::TagMethod;
use lua_types::opcode::Instruction;
use crate::state::LuaState;

/// TODO(phase-b): lua-types does not yet expose `OpCode`. Stubbed locally with
/// all 5.4 opcodes so call sites in vm.rs/debug.rs resolve; the real numeric
/// values and per-opcode mode flags live in `lua-types/src/opcode.rs` once
/// translated.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[allow(non_camel_case_types)]
pub enum OpCode {
    Move, LoadI, LoadF, LoadK, LoadKX, LoadKx, LoadFalse, LFalseSkip, LoadTrue, LoadNil,
    GetUpVal, GetUpval, SetUpVal, GetTabUp, GetTable, GetI, GetField, SetTabUp, SetTable, SetI, SetField,
    NewTable, Self_,
    AddI, AddK, SubK, MulK, ModK, PowK, DivK, IDivK, BAndK, BOrK, BXOrK,
    Add, Sub, Mul, Mod, Pow, Div, IDiv, BAnd, BOr, BXOr, Shl, Shr, ShlI, ShrI,
    MmBin, MmBinI, MmBinK,
    Unm, BNot, Not, Len, Concat,
    Close, Tbc, Jmp,
    Eq, Lt, Le, EqK, EqI, LtI, LeI, GtI, GeI, Test, TestSet,
    Call, TailCall, Return,
    ForLoop, ForPrep, TForPrep, TForCall, TForLoop,
    SetList, Closure, VarArg, VarArgPrep, ExtraArg,
    Return0, Return1,
}

/// TODO(phase-b): Instruction accessor extension trait. The real per-mode
/// decode helpers live in `lua-types::opcode` once translated. Stubbed locally
/// so call sites resolve; bodies are inferred from `lopcodes.h` macro shapes.
pub trait InstructionExt {
    fn opcode(&self) -> OpCode;
    fn arg_a(&self) -> i32;
    fn arg_b(&self) -> i32;
    fn arg_c(&self) -> i32;
    fn arg_k(&self) -> i32;
    fn arg_ax(&self) -> i32;
    fn arg_bx(&self) -> i32;
    fn arg_s_b(&self) -> i32;
    fn arg_s_c(&self) -> i32;
    fn arg_s_j(&self) -> i32;
    fn arg_s_bx(&self) -> i32;
    fn test_k(&self) -> bool;
    fn test_a_mode(&self) -> bool;
    fn is_mm_mode(&self) -> bool;
    fn is_vararg_prep(&self) -> bool;
    fn is_in_top(&self) -> bool;
}

impl InstructionExt for Instruction {
    fn opcode(&self) -> OpCode {
        // TODO(phase-b): map raw u8 → OpCode variant. For now panic at decode time
        // so unit tests catch missing translation rather than silently miscomputing.
        todo!("phase-b: OpCode decode from instruction word")
    }
    fn arg_a(&self) -> i32 { ((self.raw() >> 7) & 0xFF) as i32 }
    fn arg_b(&self) -> i32 { ((self.raw() >> 16) & 0xFF) as i32 }
    fn arg_c(&self) -> i32 { ((self.raw() >> 24) & 0xFF) as i32 }
    fn arg_k(&self) -> i32 { ((self.raw() >> 15) & 0x1) as i32 }
    fn arg_ax(&self) -> i32 { (self.raw() >> 7) as i32 }
    fn arg_bx(&self) -> i32 { (self.raw() >> 15) as i32 }
    fn arg_s_b(&self) -> i32 { self.arg_b() - 0x7F }
    fn arg_s_c(&self) -> i32 { self.arg_c() - 0x7F }
    fn arg_s_j(&self) -> i32 { self.arg_ax() - 0x1FFFF }
    fn arg_s_bx(&self) -> i32 { self.arg_bx() - 0xFFFF }
    fn test_k(&self) -> bool { (self.raw() & (1 << 15)) != 0 }
    fn test_a_mode(&self) -> bool { todo!("phase-b: test_a_mode") }
    fn is_mm_mode(&self) -> bool { todo!("phase-b: is_mm_mode") }
    fn is_vararg_prep(&self) -> bool { todo!("phase-b: is_vararg_prep") }
    fn is_in_top(&self) -> bool { todo!("phase-b: is_in_top") }
}

// ─── Constants ───────────────────────────────────────────────────────────────

/// C: #define MAXTAGLOOP 2000
/// Limit for tag-method chains to avoid infinite loops.
const MAX_TAG_LOOP: i32 = 2000;

/// C: NBITS — number of bits in lua_Integer (i64).
const NBITS: u32 = 64;

// ─── F2Imod — float-to-integer rounding mode ────────────────────────────────

/// C: `typedef enum { F2Ieq, F2Ifloor, F2Iceil } F2Imod;`
/// Rounding mode for float→integer coercions.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum F2Imod {
    /// Accept only exact integral values (no rounding).
    Eq,
    /// Round toward negative infinity.
    Floor,
    /// Round toward positive infinity.
    Ceil,
}

// ─── Integer-overflow-safe helpers ──────────────────────────────────────────

/// C: `intop(+, a, b)` — wrapping add on i64 operands.
#[inline]
fn intop_add(a: i64, b: i64) -> i64 {
    (a as u64).wrapping_add(b as u64) as i64
}

/// C: `intop(-, a, b)` — wrapping sub.
#[inline]
fn intop_sub(a: i64, b: i64) -> i64 {
    (a as u64).wrapping_sub(b as u64) as i64
}

/// C: `intop(*, a, b)` — wrapping mul.
#[inline]
fn intop_mul(a: i64, b: i64) -> i64 {
    (a as u64).wrapping_mul(b as u64) as i64
}

/// C: `intop(>>, x, -y)` or `intop(<<, x, y)` — wrapping shift.
/// Shifts via unsigned intermediate to get logical (not arithmetic) semantics.
#[inline]
fn intop_shr(x: i64, n: u32) -> i64 {
    // PERF(port): logical right shift via unsigned; matches C unsigned semantics
    (x as u64 >> n) as i64

/// ORDER OP — must match `lopcodes.h` exactly.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
#[repr(u8)]
pub enum OpCode {
    // C: OP_MOVE,/*  A B    R[A] := R[B]  */
    Move = 0,
    // C: OP_LOADI,/* A sBx  R[A] := sBx  */
    LoadI,
    // C: OP_LOADF,/* A sBx  R[A] := (lua_Number)sBx  */
    LoadF,
    // C: OP_LOADK,/* A Bx   R[A] := K[Bx]  */
    LoadK,
    // C: OP_LOADKX,/* A     R[A] := K[extra arg]  */
    LoadKX,
    // C: OP_LOADFALSE,/* A  R[A] := false  */
    LoadFalse,
    // C: OP_LFALSESKIP,/* A R[A] := false; pc++  */
    LFalseSkip,
    // C: OP_LOADTRUE,/* A   R[A] := true  */
    LoadTrue,
    // C: OP_LOADNIL,/* A B  R[A], R[A+1], ..., R[A+B] := nil  */
    LoadNil,
    // C: OP_GETUPVAL,/* A B R[A] := UpValue[B]  */
    GetUpVal,
    // C: OP_SETUPVAL,/* A B UpValue[B] := R[A]  */
    SetUpVal,

    // C: OP_GETTABUP,/* A B C  R[A] := UpValue[B][K[C]:shortstring]  */
    GetTabUp,
    // C: OP_GETTABLE,/* A B C  R[A] := R[B][R[C]]  */
    GetTable,
    // C: OP_GETI,/*    A B C  R[A] := R[B][C]  */
    GetI,
    // C: OP_GETFIELD,/* A B C  R[A] := R[B][K[C]:shortstring]  */
    GetField,

    // C: OP_SETTABUP,/* A B C  UpValue[A][K[B]:shortstring] := RK(C)  */
    SetTabUp,
    // C: OP_SETTABLE,/* A B C  R[A][R[B]] := RK(C)  */
    SetTable,
    // C: OP_SETI,/*    A B C  R[A][B] := RK(C)  */
    SetI,
    // C: OP_SETFIELD,/* A B C  R[A][K[B]:shortstring] := RK(C)  */
    SetField,

    // C: OP_NEWTABLE,/* A B C k  R[A] := {}  */
    NewTable,

    // C: OP_SELF,/* A B C  R[A+1] := R[B]; R[A] := R[B][RK(C):string]  */
    // PORT NOTE: `self` is a Rust keyword; renamed to `Self_`.
    Self_,

    // C: OP_ADDI,/* A B sC  R[A] := R[B] + sC  */
    AddI,

    // C: OP_ADDK,/* A B C  R[A] := R[B] + K[C]:number  */
    AddK,
    // C: OP_SUBK,/* A B C  R[A] := R[B] - K[C]:number  */
    SubK,
    // C: OP_MULK,/* A B C  R[A] := R[B] * K[C]:number  */
    MulK,
    // C: OP_MODK,/* A B C  R[A] := R[B] % K[C]:number  */
    ModK,
    // C: OP_POWK,/* A B C  R[A] := R[B] ^ K[C]:number  */
    PowK,
    // C: OP_DIVK,/* A B C  R[A] := R[B] / K[C]:number  */
    DivK,
    // C: OP_IDIVK,/* A B C  R[A] := R[B] // K[C]:number  */
    IDivK,

    // C: OP_BANDK,/* A B C  R[A] := R[B] & K[C]:integer  */
    BAndK,
    // C: OP_BORK,/*  A B C  R[A] := R[B] | K[C]:integer  */
    BOrK,
    // C: OP_BXORK,/* A B C  R[A] := R[B] ~ K[C]:integer  */
    BXorK,

    // C: OP_SHRI,/* A B sC  R[A] := R[B] >> sC  */
    ShrI,
    // C: OP_SHLI,/* A B sC  R[A] := sC << R[B]  */
    ShlI,

    // C: OP_ADD,/*  A B C  R[A] := R[B] + R[C]  */
    Add,
    // C: OP_SUB,/*  A B C  R[A] := R[B] - R[C]  */
    Sub,
    // C: OP_MUL,/*  A B C  R[A] := R[B] * R[C]  */
    Mul,
    // C: OP_MOD,/*  A B C  R[A] := R[B] % R[C]  */
    Mod,
    // C: OP_POW,/*  A B C  R[A] := R[B] ^ R[C]  */
    Pow,
    // C: OP_DIV,/*  A B C  R[A] := R[B] / R[C]  */
    Div,
    // C: OP_IDIV,/* A B C  R[A] := R[B] // R[C]  */
    IDiv,

    // C: OP_BAND,/* A B C  R[A] := R[B] & R[C]  */
    BAnd,
    // C: OP_BOR,/*  A B C  R[A] := R[B] | R[C]  */
    BOr,
    // C: OP_BXOR,/* A B C  R[A] := R[B] ~ R[C]  */
    BXor,
    // C: OP_SHL,/*  A B C  R[A] := R[B] << R[C]  */
    Shl,
    // C: OP_SHR,/*  A B C  R[A] := R[B] >> R[C]  */
    Shr,

    // C: OP_MMBIN,/*  A B C    call C metamethod over R[A] and R[B]  */
    MmBin,
    // C: OP_MMBINI,/* A sB C k call C metamethod over R[A] and sB  */
    MmBinI,
    // C: OP_MMBINK,/* A B C k  call C metamethod over R[A] and K[B]  */
    MmBinK,

    // C: OP_UNM,/*    A B  R[A] := -R[B]  */
    Unm,
    // C: OP_BNOT,/*   A B  R[A] := ~R[B]  */
    BNot,
    // C: OP_NOT,/*    A B  R[A] := not R[B]  */
    Not,
    // C: OP_LEN,/*    A B  R[A] := #R[B]  */
    Len,

    // C: OP_CONCAT,/* A B  R[A] := R[A].. ... ..R[A + B - 1]  */
    Concat,

    // C: OP_CLOSE,/* A  close all upvalues >= R[A]  */
    Close,
    // C: OP_TBC,/*   A  mark variable A "to be closed"  */
    Tbc,
    // C: OP_JMP,/*   sJ  pc += sJ  */
    Jmp,

    // C: OP_EQ,/* A B k  if ((R[A] == R[B]) ~= k) then pc++  */
    Eq,
    // C: OP_LT,/* A B k  if ((R[A] <  R[B]) ~= k) then pc++  */
    Lt,
    // C: OP_LE,/* A B k  if ((R[A] <= R[B]) ~= k) then pc++  */
    Le,

    // C: OP_EQK,/* A B k   if ((R[A] == K[B]) ~= k) then pc++  */
    EqK,
    // C: OP_EQI,/* A sB k  if ((R[A] == sB) ~= k) then pc++  */
    EqI,
    // C: OP_LTI,/* A sB k  if ((R[A] < sB) ~= k) then pc++  */
    LtI,
    // C: OP_LEI,/* A sB k  if ((R[A] <= sB) ~= k) then pc++  */
    LeI,
    // C: OP_GTI,/* A sB k  if ((R[A] > sB) ~= k) then pc++  */
    GtI,
    // C: OP_GEI,/* A sB k  if ((R[A] >= sB) ~= k) then pc++  */
    GeI,

    // C: OP_TEST,/*    A k    if (not R[A] == k) then pc++  */
    Test,
    // C: OP_TESTSET,/* A B k  if (not R[B] == k) then pc++ else R[A] := R[B]  */
    TestSet,

    // C: OP_CALL,/*     A B C    R[A], ... ,R[A+C-2] := R[A](R[A+1], ... ,R[A+B-1])  */
    Call,
    // C: OP_TAILCALL,/* A B C k  return R[A](R[A+1], ... ,R[A+B-1])  */
    TailCall,

    // C: OP_RETURN,/*  A B C k  return R[A], ... ,R[A+B-2]  */
    Return,
    // C: OP_RETURN0,/*           return  */
    Return0,
    // C: OP_RETURN1,/* A         return R[A]  */
    Return1,

    // C: OP_FORLOOP,/* A Bx  update counters; if loop continues then pc-=Bx  */
    ForLoop,
    // C: OP_FORPREP,/* A Bx  check values and prepare; if not to run then pc+=Bx+1  */
    ForPrep,

/// In C: stack-allocated in `body()`, chained via raw `*prev` pointer.
/// In Rust: heap-allocated via `Option<Box<FuncState>>` in LexState.
#[derive(Debug)]
pub struct FuncState {
    /// C: f — the Proto being built.
    /// PORT NOTE: types.tsv maps this to GcRef<LuaProto>; we use Box<LuaProto>
    ///   during compilation to avoid RefCell overhead. close_func hands it to
    ///   the GC/parent at close time.
    pub f: Box<LuaProto>,
    /// C: prev — enclosing FuncState (raw pointer in C; owned Box here).
    pub prev: Option<Box<FuncState>>,
    /// C: bl — innermost active block
    pub bl: Option<Box<BlockCnt>>,
    /// C: pc — next bytecode position to emit
    pub pc: i32,
    /// C: lasttarget — pc of last 'jump label'
    pub lasttarget: i32,
    /// C: previousline — last line saved in lineinfo
    pub previousline: i32,
    /// C: nk — number of constants emitted
    pub nk: i32,
    /// C: np — number of nested prototypes emitted
    pub np: i32,
    /// C: nabslineinfo — number of absolute line-info records
    pub nabslineinfo: i32,
    /// C: firstlocal — index of first local var in dyd.actvar
    pub firstlocal: i32,
    /// C: firstlabel — index of first label in dyd.label
    pub firstlabel: i32,
    /// C: ndebugvars — entries in f.locvars
    pub ndebugvars: i16,
    /// C: nactvar — number of active locals
    pub nactvar: u8,
    /// C: nups — number of upvalues
    pub nups: u8,
    /// C: freereg — next free register
    pub freereg: u8,
    /// C: iwthabs — instructions since last absolute line info
    pub iwthabs: u8,
    /// C: needclose — function must close upvalues on return
    pub needclose: bool,
}

