769	    // PERF(port): Vec::push handles growth
770	    if fs.f.code.len() <= fs.pc as usize {
771	        fs.f.code.resize(fs.pc as usize + 1, Instruction::default());
772	    }
773	    fs.f.code[fs.pc as usize] = i;
774	    fs.pc += 1;
