/// C: static void restassign(LexState *ls, struct LHS_assign *lh, int nvars)
fn restassign(
    ls: &mut LexState,
    state: &mut LuaState,
    lh: &mut LhsAssign,
    nvars: i32,
) -> Result<(), LuaError> {
    // C: check_condition(ls, vkisvar(lh->v.k), "syntax error")
    if !lh.v.k.is_var() {
        return Err(LuaError::syntax(format_args!("syntax error")));
